parameters.jsonBody:
={{ {
  "content": (function(){
    const b = $json.body ?? $json;
    const items = (b.items || []).slice(0,5);
    const lines = items.map(i => {
      const ld = (i.dist_ld !== null && i.dist_ld !== undefined) ? (Number(i.dist_ld).toFixed(2) + ' LD') : (i.dist_au ? (Number(i.dist_au).toFixed(6) + ' AU') : '');
      const v = (i.v_rel_km_s !== null && i.v_rel_km_s !== undefined) ? (' @ ' + Number(i.v_rel_km_s).toFixed(1) + ' km/s') : '';
      const cd = i.cd ? (i.cd + ' UTC') : '';
      return `• ${i.des || 'unknown'} — ${ld}${v} — ${cd}`.trim();
    }).join('\n');
    const hdr = `PDF JPL CAD: ${b.count ?? items.length} approaches ≤${b.dist_max_au ?? '0.01'} AU (next ${b.days_ahead ?? 14}d)`;
    const src = b.source ? (`Source: ${b.source}`) : '';
    return [hdr, lines, src].filter(Boolean).join('\n');
  })()
} }}
